-- Database: perpustakaan
-- Buat struktur database perpustakaan untuk phpMyAdmin lengkap dengan 50 Koleksi Buku Real-Time

CREATE DATABASE IF NOT EXISTS `perpustakaan` DEFAULT CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci;
USE `perpustakaan`;

-- --------------------------------------------------------

-- Struktur dari tabel `books`
CREATE TABLE IF NOT EXISTS `books` (
  `id` bigint(20) unsigned NOT NULL AUTO_INCREMENT,
  `title` varchar(255) NOT NULL,
  `author` varchar(255) NOT NULL,
  `category` varchar(255) NOT NULL,
  `year` int(11) NOT NULL,
  `shelfLocation` varchar(255) NOT NULL,
  `totalCopies` int(11) NOT NULL,
  `availableCopies` int(11) NOT NULL,
  `synopsis` text NOT NULL,
  `rating` decimal(3,1) NOT NULL DEFAULT 5.0,
  `coverUrl` varchar(500) DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

-- Dumping data untuk tabel `books` dengan semua 50 buku dari sasis sistem utama

-- --------------------------------------------------------

-- Struktur dari tabel `loans`
CREATE TABLE IF NOT EXISTS `loans` (
  `id` bigint(20) unsigned NOT NULL AUTO_INCREMENT,
  `bookId` bigint(20) unsigned NOT NULL,
  `bookTitle` varchar(255) NOT NULL,
  `memberId` varchar(255) NOT NULL,
  `memberName` varchar(255) NOT NULL,
  `borrowDate` date NOT NULL,
  `dueDate` date NOT NULL,
  `returnDate` date DEFAULT NULL,
  `status` varchar(255) NOT NULL DEFAULT 'borrowed',
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `bookId` (`bookId`),
  CONSTRAINT `loans_ibfk_1` FOREIGN KEY (`bookId`) REFERENCES `books` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

